children.text:
body { margin: 0; }
#test, #image, #white, .blue, .failure {
    position: absolute;
    top: 70px;
}
#test, #image { left: 10px; }
#image { z-index: -2; }

#white {
    left: 60px;
    width: 10px;
    height: 100px;
    background-color: white;
    z-index: -1;
}
#test {
  font: 50px/1 Ahem;
  width: 200px;
  color: rgb(0,100,0);
  z-index: 2;
}
#shape-image {
    float: left;
    width: 100px;
    height: 100px;
    shape-outside: url("support/left-half-rectangle-50.svg");
    shape-margin: 10px;
    shape-image-threshold: 0.55;
}
.blue {
    width: 2px;
    height: 100px;
    background-color: blue;
    z-index: 3;
}
.left-line { left: 65px; }
.right-line { left: 125px; }

.failure {
    left: 70px;
    width: 50px;
    height: 100px;
    background-color: red;
    z-index: 1;
}
